import{c as o,Q as r,j as a,m as t}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"速通offer上线了！看看你能从这里带走什么","description":"","frontmatter":{"title":"速通offer上线了！看看你能从这里带走什么","date":"2026-05-26T00:00:00.000Z","tags":"公告"},"headers":[],"relativePath":"blog/hello-world.md","filePath":"blog/hello-world.md","lastUpdated":1780152593000}'),l={name:"blog/hello-world.md"};function n(s,e,i,d,p,f){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="🎮-速通offer上线了-看看你能从这里带走什么" tabindex="-1">🎮 速通offer上线了！看看你能从这里带走什么 <a class="header-anchor" href="#🎮-速通offer上线了-看看你能从这里带走什么" aria-label="Permalink to &quot;🎮 速通offer上线了！看看你能从这里带走什么&quot;">​</a></h1><p>大家好，我是小速。</p><p>速通offer今天正式上线了。</p><p>名字很直白——<strong>速通offer</strong>。就像打游戏有速通攻略一样，面试求职也可以有一条清晰的通关路线。</p><h2 id="目前有什么" tabindex="-1">目前有什么 <a class="header-anchor" href="#目前有什么" aria-label="Permalink to &quot;目前有什么&quot;">​</a></h2><p>第一期上线的是<strong>技术岗面试攻略</strong>，也是目前内容最完整的板块：</p><ul><li><strong>图解网络</strong> — 500张图+15万字，HTTP/HTTPS/TCP/UDP/IP 全覆盖</li><li><strong>图解系统</strong> — 400张图+16万字，CPU/内存/进程/文件系统/网络系统</li><li><strong>图解MySQL</strong> — 索引/锁/事务/MVCC/日志</li><li><strong>图解Redis</strong> — 数据结构/持久化/集群/缓存</li><li><strong>面试八股题</strong> — Java/Go/C++/Spring/测试开发</li><li><strong>大厂面经</strong> — 字节/腾讯/阿里/美团等真实面试真题</li></ul><h2 id="即将上线" tabindex="-1">即将上线 <a class="header-anchor" href="#即将上线" aria-label="Permalink to &quot;即将上线&quot;">​</a></h2><p>产品、运营、设计、销售各岗位的面试攻略也在陆续整理中。每个岗位都会有自己专属的速通路线图。</p><h2 id="怎么用" tabindex="-1">怎么用 <a class="header-anchor" href="#怎么用" aria-label="Permalink to &quot;怎么用&quot;">​</a></h2><p>左上角导航栏选你对应的岗位，跟着侧边栏一路往下刷就行。支持本地搜索，遇到不懂的直接搜。</p><p>跟着小速，面试通关就这么简单。</p><hr><p><em>有什么建议或者想投稿的，欢迎随时说。</em></p>',14)])])}const c=o(l,[["render",n]]);export{g as __pageData,c as default};
